import React, { FC, useRef, useEffect, useState } from 'react';
import { Helmet } from 'react-helmet';
import { Button } from './styles';

const enrollFormUrl = 'https://liana345201.typeform.com/to/B0f3OT5m';

const EnrollNowButton: FC = () => {
  const buttonRef = useRef(null);
  const [typeformEmbed, setTypeformEmbed] = useState(null);

  useEffect(() => {
    // eslint-disable-next-line @typescript-eslint/ban-ts-ignore
    // @ts-ignore
    const { typeformEmbed: tfe } = window;
    setTypeformEmbed(tfe);
    console.log('here', tfe);
  }, []);

  const openForm = () =>
    typeformEmbed?.makePopup(enrollFormUrl, {
      mode: 'popup',
      autoOpen: true,
    });

  return (
    <>
      <Helmet>
        <script src="https://embed.typeform.com/embed.js" />
      </Helmet>
      <Button disabled={!typeformEmbed} onClick={openForm} ref={buttonRef}>
        Enroll now
      </Button>
    </>
  );
};

export default EnrollNowButton;
